  ('medical-tech-moex-20968', 'medical-tech', 'medical-tech-moex-093-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '下列有關腸病毒之敘述何者為錯誤？ 好發於嬰幼兒 無菌性腦膜炎（Aseptic meningitis）為嬰兒感染常見之臨床表徵 主要傳染途徑為糞口 腸病毒極易死亡，無法於室溫久存', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "1d862fed5162", "answer_pdf_sha1": "5c7487e6a69d", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 55, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20969', 'medical-tech', 'medical-tech-moex-093-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '下列關於Measles virus之敘述，何者為正確？ 是Myxoviridae科 有四種血清型 可能會引起subacute sclerosing panencephalitis（SSPE）之後遺症 具有hemagglutinin（H）和neuraminidase（N），可凝集猴子紅血球', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "1d862fed5162", "answer_pdf_sha1": "5c7487e6a69d", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 56, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20970', 'medical-tech', 'medical-tech-moex-093-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '下列何者屬於DNA病毒？ 輪狀病毒（Rotavirus）  漢他病毒（Hantavirus）  登革病毒（Dengue virus）  JC病毒（JC virus）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "1d862fed5162", "answer_pdf_sha1": "5c7487e6a69d", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 57, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20971', 'medical-tech', 'medical-tech-moex-093-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '下列何種病毒之核酸為單股RNA？ 腸病毒（Enterovirus）    腺病毒（Adenovirus） 微小病毒（Parvovirus B19）  呼腸孤病毒（Reovirus）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "1d862fed5162", "answer_pdf_sha1": "5c7487e6a69d", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 58, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20972', 'medical-tech', 'medical-tech-moex-093-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '下列關於Rubella virus之敘述，何者為正確？ 共有兩種血清型 屬於Rhabdoviridae科 病毒之細胞培養不容易，作血清學檢查可迅速得到診斷 懷孕早期被感染不會造成胎兒之先天畸形', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "1d862fed5162", "answer_pdf_sha1": "5c7487e6a69d", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 59, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20973', 'medical-tech', 'medical-tech-moex-093-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '下列何種病毒有可能在新生兒出生時，經產道感染而造成全身性的症狀？ 艾科病毒（Echovirus）    單純 疹病毒（Herpes simplex virus） 71型腸病毒（Enterovirus type 71）  腺病毒（Adenovirus）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "1d862fed5162", "answer_pdf_sha1": "5c7487e6a69d", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 60, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20974', 'medical-tech', 'medical-tech-moex-093-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '披衣菌（Chlamydia）最適合在下列何種細胞株生長？ 子宮頸癌細胞（human cervical cancer; McCoy） 人類胚胎肺臟細胞（Human embryonic lung cells; HEL） 人類胚胎腎臟細胞（Human embryonic kidney cells; HEK） T-細胞（T-cells）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "1d862fed5162", "answer_pdf_sha1": "5c7487e6a69d", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 61, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20975', 'medical-tech', 'medical-tech-moex-093-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '水痘帶狀 疹病毒（Varicella-zoster virus）利用下列何種細胞培養較合適？ MK-2細胞    Vero細胞 非洲綠猴腎細胞（Green monkey kidney cell）  人類胚胎肺臟細胞（Human embryonic lung cell）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "1d862fed5162", "answer_pdf_sha1": "5c7487e6a69d", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 62, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20976', 'medical-tech', 'medical-tech-moex-093-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '人類乳突狀瘤病毒（Human papillomavirus; HPV）感染後，主要在下列何處複製，誘導細胞增生？ 血液循環  結締組織  表皮及黏膜上皮  神經組織', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "1d862fed5162", "answer_pdf_sha1": "5c7487e6a69d", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 63, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20977', 'medical-tech', 'medical-tech-moex-093-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '下列有關B型肝炎病毒（Hepatitis B virus）之敘述，何者是錯誤的？ 是一種DNA病毒    可利用一般實驗室細胞培養 具有反轉錄 （Reverse transcriptase）  基因體之複製在細胞質內進行', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "1d862fed5162", "answer_pdf_sha1": "5c7487e6a69d", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 64, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL)
